export const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3333';

// Экспорт по умолчанию
const api = {
  url: BASE_URL,
  getCategoryImageUrl: (img) => `${BASE_URL}/category_img/${img}`,
};

export default api;
